#include<bits/stdc++.h>
using namespace std;
bool vis[10001];
int n,k;
int main()
{
    scanf("%d%d",&n,&k);
    int cnt=0,ans=1;
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        if(!vis[x])
        {
            cnt++;
            vis[x]=1;
        }
        if(cnt==k)
        {
            memset(vis,0,sizeof(vis));
            cnt=0;
            ans++;
        }
    }
    printf("%d",ans);
    return 0;
}
